//+------------------------------------------------------------------+
//|  CTR_Reclaim_GBPUSD_v2_3.mq5                                     |
//|  Counter Trend Reclaim — GBP/USD M5 Edition                      |
//|                                                                  |
//|  CHANGELOG v2.3 (vs v2.2):                                       |
//|  ─ Days: Solo MARTES activo por defecto (análisis del .set de    |
//|    Liquid Pours Xtreme GBPUSD → Set098_UTCm4_to_UTCp3)          |
//|  ─ GMT_Offset default = 3 (FundingPips verano/EDT)               |
//|  ─ AutoSafeMode: padding dinámico en tester para stops inválidos  |
//|  ─ SafeModeFromTF: valida mínimo de stop contra rango H1         |
//|  ─ ToleranceMinutes = ±1 min en detección de key candle          |
//|  ─ Fórmula timezone corregida: Server = NY_EDT + 4 + GMT_Offset  |
//|  ─ Todos los bugfixes de v2.2 conservados                        |
//+------------------------------------------------------------------+
#property copyright "CTR Reclaim EA"
#property version   "2.30"
#property strict

#include <Trade\Trade.mqh>
#include <Trade\SymbolInfo.mqh>

//--- Custom enum para dirección de trade
enum ENUM_CTR_DIRECTION
  {
   DIR_BOTH  = 0, // Both (Buy & Sell)
   DIR_BUY   = 1, // Buy Only
   DIR_SELL  = 2  // Sell Only
  };

//=== INPUTS ========================================================

input group "══ IDENTIDAD ══"
input ulong  MagicNumber      = 1010;         // Magic number del EA
input bool   FilterByMagic    = true;         // Filtrar posiciones por magic

input group "══ RIESGO ══"
input double RiskPercent      = 1.0;          // Riesgo % por trade (sobre balance)
input double FixedLots        = 0.0;          // Lotes fijos (0 = auto por riesgo)
input bool   UseEquityForRisk = false;        // Usar equity en lugar de balance

input group "══ ESTRATEGIA ══"
input int             SL_ticks  = 110;        // Stop Loss en ticks (110 = 11 pips)
input int             TP_ticks  = 290;        // Take Profit en ticks (290 = 29 pips)
input ENUM_CTR_DIRECTION TradeDir = DIR_BOTH; // Dirección permitida
input int             WindowBars = 12;        // Barras M5 tras key candle para buscar sweep

input group "══ KEY CANDLE (HORA NY) ══"
input int  NY_Hour    = 8;    // Hora en NY (8 = 8 AM EDT)
input int  NY_Minute  = 45;   // Minuto en NY
input int  GMT_Offset = 3;    // Offset del servidor (3=FundingPips verano, 2=invierno)
input int  ToleranceMinutes = 1; // Tolerancia ±min en búsqueda de key candle

input group "══ SAFE MODE (TESTER) ══"
input bool AutoSafeMode   = true;  // Activar safe mode en Strategy Tester
input int  SafePadPoints  = 6;     // Puntos extra al SL en safe mode
input bool CheckH1Range   = true;  // Validar que SL >= rango de la barra H1 actual * factor
input double H1RangeFactor = 0.15; // SL mínimo = H1_range * factor (evita stops inválidos)

input group "══ DÍAS DE TRADING ══"
input bool TradeSunday    = false; // Domingo
input bool TradeMonday    = false; // Lunes    ← Off según análisis GBPUSD
input bool TradeTuesday   = true;  // Martes   ← Solo día activo en Set098
input bool TradeWednesday = false; // Miércoles
input bool TradeThursday  = false; // Jueves
input bool TradeFriday    = false; // Viernes  ← Off según análisis GBPUSD

input group "══ FILTROS ══"
input int MaxTradesPerDay = 1;   // Máximo trades por día
input int MaxSpreadPoints = 30;  // Spread máximo permitido (puntos)
input int SlippagePoints  = 10;  // Slippage máximo

input group "══ BREAKEVEN / PARCIALES ══"
input bool   EnableBreakeven = false;  // Activar breakeven
input double BreakevenPips   = 15.0;   // Pips de ganancia para mover BE
input bool   EnablePartials  = false;  // Activar cierre parcial
input double PartialPips     = 14.0;   // Pips de ganancia para parcial
input double PartialPercent  = 50.0;   // % del volumen a cerrar

input group "══ DISPLAY & DIAGNÓSTICO ══"
input bool ShowDashboard = true;   // Mostrar panel en gráfico
input bool DrawLevels    = true;   // Dibujar líneas H/L de key candle
input bool DebugMode     = false;  // Logging detallado en Experts tab
input bool ExportCSV     = true;   // Exportar señales a CSV

//=== GLOBALES ======================================================

CTrade      m_trade;
CSymbolInfo m_symbol;

// Key candle del día
double   g_KeyHigh    = 0.0;
double   g_KeyLow     = 0.0;
datetime g_KeyTime    = 0;
bool     g_KeyMarked  = false;

// Estado diario
int      g_TradesToday = 0;
datetime g_LastDate    = 0;
bool     g_PartialDone = false;

// Tiempo de key candle en hora servidor (calculado en OnInit)
int      g_SrvHour = 0;
int      g_SrvMin  = 0;

// Fill mode detectado
string   g_Filling = "RETURN";

// CSV
int      g_CSV     = INVALID_HANDLE;

// Para detectar nueva barra (procesar 1 vez por bar)
datetime g_LastBarTime = 0;

//+------------------------------------------------------------------+
//| OnInit                                                           |
//+------------------------------------------------------------------+
int OnInit()
  {
   if(!m_symbol.Name(_Symbol))
     {
      Print("[CTR] ERROR: No se pudo inicializar símbolo ", _Symbol);
      return INIT_FAILED;
     }
   m_symbol.Refresh();

   // ── Calcular hora del servidor equivalente a NY EDT 8:45 ───────
   // UTC    = NY_EDT + 4        (NY EDT = UTC-4)
   // Server = UTC + GMT_Offset  = NY_EDT + 4 + GMT_Offset
   // FundingPips verano (GMT+3):  8 + 4 + 3 = 15:45 ✓
   // FundingPips invierno (GMT+2): usuario pone GMT_Offset=2 → 8+5+2=15
   //   (en invierno NY=EST=UTC-5, pero FundingPips también baja a GMT+2,
   //    entonces sigue siendo 15:45 servidor — el offset neto siempre es +7)
   g_SrvHour = (NY_Hour + 4 + GMT_Offset) % 24;
   g_SrvMin  = (NY_Minute / 5) * 5;  // auto-snap al grid M5

   // ── Detectar fill mode del broker ─────────────────────────────
   DetectFillMode();

   // ── Configurar CTrade ─────────────────────────────────────────
   m_trade.SetExpertMagicNumber(MagicNumber);
   m_trade.SetDeviationInPoints(SlippagePoints);
   m_trade.SetTypeFilling(GetFillingEnum());

   // ── Init CSV ──────────────────────────────────────────────────
   if(ExportCSV) InitCSV();

   // ── Log de inicio ─────────────────────────────────────────────
   PrintFormat("[CTR v2.3] Init OK | %s M5 | Key candle servidor: %02d:%02d | Fill: %s",
               _Symbol, g_SrvHour, g_SrvMin, g_Filling);
   PrintFormat("[CTR v2.3] Días activos: %s%s%s%s%s | SL=%d ticks | TP=%d ticks | RR 1:%.2f",
               TradeMonday    ? "Lun " : "",
               TradeTuesday   ? "Mar " : "",
               TradeWednesday ? "Mié " : "",
               TradeThursday  ? "Jue " : "",
               TradeFriday    ? "Vie"  : "",
               SL_ticks, TP_ticks, (double)TP_ticks / SL_ticks);

   return INIT_SUCCEEDED;
  }

//+------------------------------------------------------------------+
//| OnDeinit                                                         |
//+------------------------------------------------------------------+
void OnDeinit(int reason)
  {
   if(g_CSV != INVALID_HANDLE)
     {
      FileClose(g_CSV);
      g_CSV = INVALID_HANDLE;
     }
   ObjectsDeleteAll(0, "CTR_");
  }

//+------------------------------------------------------------------+
//| OnTick — tick principal                                          |
//+------------------------------------------------------------------+
void OnTick()
  {
   if(!m_symbol.RefreshRates()) return;

   datetime now = TimeCurrent();
   MqlDateTime dt;
   TimeToStruct(now, dt);

   // 1. Reset estado si es día nuevo
   ResetDailyIfNeeded(dt);

   // 2. Filtro de día
   if(!IsTradingDay(dt.day_of_week)) return;

   // 3. Intentar marcar key candle del día
   if(!g_KeyMarked) TryScanKeyCandle(dt);
   if(!g_KeyMarked) return;

   // 4. Límite de trades
   if(g_TradesToday >= MaxTradesPerDay) return;

   // 5. Filtro de spread
   double spread = (m_symbol.Ask() - m_symbol.Bid()) / m_symbol.Point();
   if(spread > MaxSpreadPoints)
     {
      if(DebugMode) PrintFormat("[CTR] Spread alto: %.0f pts > %d", spread, MaxSpreadPoints);
      return;
     }

   // 6. Procesar señales sólo en nueva barra M5
   datetime curBar = iTime(_Symbol, PERIOD_M5, 0);
   if(curBar != g_LastBarTime)
     {
      g_LastBarTime = curBar;
      CheckSweepSignal();
     }

   // 7. Gestión de posiciones abiertas
   if(EnableBreakeven || EnablePartials) ManageOpenPositions();

   // 8. Dashboard
   if(ShowDashboard) DrawDashboard(spread);
  }

//+------------------------------------------------------------------+
//| Resetear estado diario                                           |
//+------------------------------------------------------------------+
void ResetDailyIfNeeded(const MqlDateTime &dt)
  {
   datetime today = StringToTime(StringFormat("%04d.%02d.%02d 00:00",
                                              dt.year, dt.mon, dt.day));
   if(today == g_LastDate) return;

   g_LastDate     = today;
   g_TradesToday  = 0;
   g_KeyMarked    = false;
   g_KeyHigh      = 0.0;
   g_KeyLow       = 0.0;
   g_KeyTime      = 0;
   g_PartialDone  = false;

   // Borrar líneas del día anterior
   ObjectDelete(0, "CTR_KH");
   ObjectDelete(0, "CTR_KL");

   if(DebugMode)
      PrintFormat("[CTR] Nuevo día %s — estado reseteado", TimeToString(today, TIME_DATE));
  }

//+------------------------------------------------------------------+
//| ¿Es día de trading?                                              |
//+------------------------------------------------------------------+
bool IsTradingDay(int dow)
  {
   switch(dow)
     {
      case 0: return TradeSunday;
      case 1: return TradeMonday;
      case 2: return TradeTuesday;
      case 3: return TradeWednesday;
      case 4: return TradeThursday;
      case 5: return TradeFriday;
      default: return false;
     }
  }

//+------------------------------------------------------------------+
//| Escanear barras históricas para encontrar la key candle del día  |
//+------------------------------------------------------------------+
void TryScanKeyCandle(const MqlDateTime &dt)
  {
   int maxLook = MathMin(iBars(_Symbol, PERIOD_M5) - 1, 288); // máx 1 día entero

   for(int i = 1; i < maxLook; i++)
     {
      datetime t = iTime(_Symbol, PERIOD_M5, i);
      MqlDateTime b;
      TimeToStruct(t, b);

      // Si ya pasamos al día anterior, detenemos
      if(b.year != dt.year || b.mon != dt.mon || b.day != dt.day) break;

      // Comparar hora y minuto con tolerancia ±ToleranceMinutes
      bool hourMatch = (b.hour == g_SrvHour);
      int  minDiff   = MathAbs(b.min - g_SrvMin);
      // Wrap-around a la hora (ej. 59 vs 0 → diff = 1)
      if(minDiff > 30) minDiff = 60 - minDiff;
      bool minMatch  = (minDiff <= ToleranceMinutes);

      if(hourMatch && minMatch)
        {
         g_KeyHigh   = iHigh(_Symbol, PERIOD_M5, i);
         g_KeyLow    = iLow (_Symbol, PERIOD_M5, i);
         g_KeyTime   = t;
         g_KeyMarked = true;

         if(DebugMode)
            PrintFormat("[CTR] Key candle @ %s | H=%.5f L=%.5f | Rango=%.1f pips",
                        TimeToString(t, TIME_DATE|TIME_MINUTES),
                        g_KeyHigh, g_KeyLow,
                        (g_KeyHigh - g_KeyLow) / (m_symbol.Point() * 10));

         if(DrawLevels)
           {
            MakeHLine("CTR_KH", g_KeyHigh, clrDodgerBlue);
            MakeHLine("CTR_KL", g_KeyLow,  clrOrangeRed);
           }
         return;
        }
     }
  }

//+------------------------------------------------------------------+
//| Detectar sweep y abrir trade                                     |
//+------------------------------------------------------------------+
void CheckSweepSignal()
  {
   if(!g_KeyMarked || g_TradesToday >= MaxTradesPerDay) return;

   // bar[1] = barra M5 cerrada que analizamos
   datetime t1 = iTime(_Symbol, PERIOD_M5, 1);

   // Debe ser DESPUÉS de la key candle
   if(t1 <= g_KeyTime) return;

   // Dentro de la ventana de WindowBars barras
   long barsSinceKey = (long)((t1 - g_KeyTime) / PeriodSeconds(PERIOD_M5));
   if(barsSinceKey < 1 || barsSinceKey > (long)WindowBars) return;

   double hi = iHigh (_Symbol, PERIOD_M5, 1);
   double lo = iLow  (_Symbol, PERIOD_M5, 1);
   double cl = iClose(_Symbol, PERIOD_M5, 1);
   double op = iOpen (_Symbol, PERIOD_M5, 1);

   // ── Señales de sweep ──────────────────────────────────────────
   // BUY:  barra penetra bajo el LOW y cierra de vuelta encima → reclaim alcista
   bool sweepBuy  = (lo  < g_KeyLow)  && (cl > g_KeyLow);
   // SELL: barra penetra sobre el HIGH y cierra de vuelta debajo → reclaim bajista
   bool sweepSell = (hi  > g_KeyHigh) && (cl < g_KeyHigh);

   // Si hay doble sweep simultáneo → señal ambigua, skip
   if(sweepBuy && sweepSell)
     {
      if(DebugMode) Print("[CTR] Doble sweep — señal ambigua, skip");
      return;
     }

   if(!sweepBuy && !sweepSell) return;

   // ── Filtro de dirección ───────────────────────────────────────
   ENUM_ORDER_TYPE orderType;
   if(sweepBuy  && TradeDir != DIR_SELL) orderType = ORDER_TYPE_BUY;
   else if(sweepSell && TradeDir != DIR_BUY) orderType = ORDER_TYPE_SELL;
   else return;

   double pt  = m_symbol.Point();
   double ask = m_symbol.Ask();
   double bid = m_symbol.Bid();

   // ── Calcular SL/TP con safe mode ─────────────────────────────
   bool inTester = (bool)MQLInfoInteger(MQL_TESTER) || (bool)MQLInfoInteger(MQL_OPTIMIZATION);
   int  safePad  = (AutoSafeMode && inTester) ? SafePadPoints : 0;

   double slDist = SL_ticks * pt + safePad * pt;

   // Validación extra: SL no menor que % del rango H1 (evita invalid stops)
   if(CheckH1Range && AutoSafeMode)
     {
      double h1High = iHigh(_Symbol, PERIOD_H1, 1);
      double h1Low  = iLow (_Symbol, PERIOD_H1, 1);
      double h1Range = h1High - h1Low;
      double slMin  = h1Range * H1RangeFactor;
      if(slDist < slMin)
        {
         if(DebugMode) PrintFormat("[CTR] SafeMode: SL ajustado de %.5f a %.5f (H1 range=%.5f)",
                                    slDist, slMin, h1Range);
         slDist = slMin;
        }
     }

   double tpDist = TP_ticks * pt;

   double entry, sl, tp;
   if(orderType == ORDER_TYPE_BUY)
     {
      entry = ask;
      sl    = NormalizeDouble(entry - slDist, _Digits);
      tp    = NormalizeDouble(entry + tpDist, _Digits);
     }
   else
     {
      entry = bid;
      sl    = NormalizeDouble(entry + slDist, _Digits);
      tp    = NormalizeDouble(entry - tpDist, _Digits);
     }

   // ── Calcular lotes ────────────────────────────────────────────
   double lots = CalculateLots(slDist);
   if(lots <= 0.0)
     {
      if(DebugMode) Print("[CTR] Cálculo de lotes falló");
      return;
     }

   // ── Enviar trade ──────────────────────────────────────────────
   if(SendTrade(orderType, lots, entry, sl, tp))
     {
      g_TradesToday++;

      if(DebugMode)
         PrintFormat("[CTR] %s enviado | lots=%.2f | entry=%.5f sl=%.5f tp=%.5f | barra=%d después de key",
                     orderType == ORDER_TYPE_BUY ? "BUY" : "SELL",
                     lots, entry, sl, tp, (int)barsSinceKey);

      if(ExportCSV)
         WriteToCSV(orderType, lots, entry, sl, tp, (int)barsSinceKey,
                    hi, lo, cl, op, slDist);
     }
  }

//+------------------------------------------------------------------+
//| Calcular tamaño de posición                                      |
//+------------------------------------------------------------------+
double CalculateLots(double slDistance)
  {
   if(FixedLots > 0.0) return FixedLots;

   double capital = UseEquityForRisk
                    ? AccountInfoDouble(ACCOUNT_EQUITY)
                    : AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmt = capital * RiskPercent / 100.0;

   double tickVal  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickSize <= 0.0 || tickVal <= 0.0)
     {
      if(DebugMode) Print("[CTR] ERROR: tickSize/tickVal inválidos");
      return 0.0;
     }

   double slInTicks = slDistance / tickSize;
   double rawLots   = riskAmt / (slInTicks * tickVal);

   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   // Truncar al step y clampear entre min/max
   double lots = MathFloor(rawLots / lotStep) * lotStep;
   lots = MathMax(lots, minLot);
   lots = MathMin(lots, maxLot);

   // ── Validación de margen (bugfix v2.2) ────────────────────────
   double marginRequired = 0.0;
   if(OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, m_symbol.Ask(), marginRequired))
     {
      double freeMargin = AccountInfoDouble(ACCOUNT_MARGIN_FREE);
      if(marginRequired > freeMargin * 0.90)
        {
         if(DebugMode)
            PrintFormat("[CTR] Margen insuficiente (need=%.2f free=%.2f) → usando minLot",
                        marginRequired, freeMargin);
         lots = minLot;
        }
     }

   return lots;
  }

//+------------------------------------------------------------------+
//| Enviar orden con lógica de retry                                 |
//+------------------------------------------------------------------+
bool SendTrade(ENUM_ORDER_TYPE ot, double lots, double entry,
               double sl, double tp)
  {
   m_trade.SetTypeFilling(GetFillingEnum());

   bool ok;
   if(ot == ORDER_TYPE_BUY)
      ok = m_trade.Buy(lots, _Symbol, entry, sl, tp, "CTR v2.3 BUY");
   else
      ok = m_trade.Sell(lots, _Symbol, entry, sl, tp, "CTR v2.3 SELL");

   if(!ok)
     {
      uint rc = m_trade.ResultRetcode();
      if(DebugMode)
         PrintFormat("[CTR] Trade rechazado: rc=%u | %s", rc, m_trade.ResultComment());

      // ── Retry 1: stops inválidos → abrir sin SL/TP, luego modify
      if(rc == 10016) // TRADE_RETCODE_INVALID_STOPS
        {
         if(DebugMode) Print("[CTR] Retry sin SL/TP...");
         if(ot == ORDER_TYPE_BUY)
            ok = m_trade.Buy (lots, _Symbol, entry, 0, 0, "CTR v2.3 BUY (noSL)");
         else
            ok = m_trade.Sell(lots, _Symbol, entry, 0, 0, "CTR v2.3 SELL (noSL)");
         if(ok)
           {
            Sleep(400);
            FixStopsOnLastPosition(sl, tp);
           }
        }

      // ── Retry 2: sin margen → intentar con lote mínimo
      if(!ok && rc == 10019) // TRADE_RETCODE_NO_MONEY
        {
         double ml = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
         if(DebugMode) PrintFormat("[CTR] Retry con lote mínimo = %.2f", ml);
         if(ot == ORDER_TYPE_BUY)
            ok = m_trade.Buy (ml, _Symbol, entry, sl, tp, "CTR v2.3 BUY (min)");
         else
            ok = m_trade.Sell(ml, _Symbol, entry, sl, tp, "CTR v2.3 SELL (min)");
        }
     }

   return ok;
  }

//+------------------------------------------------------------------+
//| Modificar stops después de open (para retry sin SL/TP)          |
//+------------------------------------------------------------------+
void FixStopsOnLastPosition(double sl, double tp)
  {
   for(int i = PositionsTotal() - 1; i >= 0; i--)
     {
      ulong ticket = PositionGetTicket(i);
      if(!PositionSelectByTicket(ticket)) continue;
      if(FilterByMagic && PositionGetInteger(POSITION_MAGIC) != (long)MagicNumber) continue;
      if(PositionGetString(POSITION_SYMBOL) != _Symbol) continue;
      m_trade.PositionModify(ticket, sl, tp);
      if(DebugMode) PrintFormat("[CTR] Stops fijados post-open: SL=%.5f TP=%.5f", sl, tp);
      return;
     }
  }

//+------------------------------------------------------------------+
//| Gestión de posiciones abiertas (BE + Parciales)                  |
//+------------------------------------------------------------------+
void ManageOpenPositions()
  {
   double pt = m_symbol.Point();

   for(int i = PositionsTotal() - 1; i >= 0; i--)
     {
      ulong ticket = PositionGetTicket(i);
      if(!PositionSelectByTicket(ticket)) continue;
      if(FilterByMagic && PositionGetInteger(POSITION_MAGIC) != (long)MagicNumber) continue;
      if(PositionGetString(POSITION_SYMBOL) != _Symbol) continue;

      long   posType   = PositionGetInteger(POSITION_TYPE);
      double openPrice = PositionGetDouble(POSITION_PRICE_OPEN);
      double curSL     = PositionGetDouble(POSITION_SL);
      double curTP     = PositionGetDouble(POSITION_TP);
      double curPrice  = (posType == POSITION_TYPE_BUY) ? m_symbol.Bid() : m_symbol.Ask();
      double pnl       = (posType == POSITION_TYPE_BUY)
                         ? (curPrice - openPrice)
                         : (openPrice - curPrice);
      double profitPips = pnl / (pt * 10.0);

      // ── Cierre parcial ────────────────────────────────────────
      if(EnablePartials && !g_PartialDone && profitPips >= PartialPips)
        {
         double vol     = PositionGetDouble(POSITION_VOLUME);
         double step    = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
         double minL    = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
         double closeVol = MathMax(MathFloor(vol * PartialPercent / 100.0 / step) * step, minL);
         if(closeVol < vol)
           {
            m_trade.PositionClosePartial(ticket, closeVol);
            g_PartialDone = true;
            if(DebugMode)
               PrintFormat("[CTR] Parcial: cerrados %.2f lotes a %.1f pips", closeVol, profitPips);
           }
        }

      // ── Breakeven ─────────────────────────────────────────────
      if(EnableBreakeven && profitPips >= BreakevenPips)
        {
         double newSL;
         bool   needsUpdate;
         if(posType == POSITION_TYPE_BUY)
           {
            newSL      = NormalizeDouble(openPrice + pt, _Digits);
            needsUpdate = (curSL < newSL);
           }
         else
           {
            newSL      = NormalizeDouble(openPrice - pt, _Digits);
            needsUpdate = (curSL > newSL || curSL == 0.0);
           }
         if(needsUpdate)
           {
            m_trade.PositionModify(ticket, newSL, curTP);
            if(DebugMode) PrintFormat("[CTR] BE activado: nuevo SL=%.5f", newSL);
           }
        }
     }
  }

//+------------------------------------------------------------------+
//| Detectar fill mode del broker (bugfix v2.2)                      |
//+------------------------------------------------------------------+
void DetectFillMode()
  {
   uint fm = (uint)SymbolInfoInteger(_Symbol, SYMBOL_FILLING_MODE);
   if((fm & SYMBOL_FILLING_FOK) == SYMBOL_FILLING_FOK) g_Filling = "FOK";
   else if((fm & SYMBOL_FILLING_IOC) == SYMBOL_FILLING_IOC) g_Filling = "IOC";
   else g_Filling = "RETURN";
  }

ENUM_ORDER_TYPE_FILLING GetFillingEnum()
  {
   if(g_Filling == "FOK")    return ORDER_FILLING_FOK;
   if(g_Filling == "IOC")    return ORDER_FILLING_IOC;
   return ORDER_FILLING_RETURN;
  }

//+------------------------------------------------------------------+
//| Dibujar línea horizontal                                         |
//+------------------------------------------------------------------+
void MakeHLine(const string name, double price, color clr)
  {
   if(ObjectFind(0, name) >= 0) ObjectDelete(0, name);
   ObjectCreate(0, name, OBJ_HLINE, 0, 0, price);
   ObjectSetInteger(0, name, OBJPROP_COLOR,   clr);
   ObjectSetInteger(0, name, OBJPROP_STYLE,   STYLE_DASH);
   ObjectSetInteger(0, name, OBJPROP_WIDTH,   1);
   ObjectSetString (0, name, OBJPROP_TOOLTIP, name + " = " + DoubleToString(price, _Digits));
  }

//+------------------------------------------------------------------+
//| Dashboard on-chart                                               |
//+------------------------------------------------------------------+
void DrawDashboard(double spread)
  {
   double rr  = (SL_ticks > 0) ? (double)TP_ticks / SL_ticks : 0.0;
   double kc  = (SL_ticks > 0) ? (double)(TP_ticks - SL_ticks) / (TP_ticks + SL_ticks) * 100.0 : 0.0;

   string txt = StringFormat(
                   "╔══ CTR Reclaim v2.3 — GBPUSD M5 ══╗\n"
                   " Key Candle: %-5s  H: %.5f\n"
                   "                    L: %.5f\n"
                   " Trades hoy: %d/%d  Spread: %.0f pts\n"
                   " SL: %d tk  TP: %d tk  RR: 1:%.2f\n"
                   " Filling: %-6s  GMT+%d\n"
                   "╚════════════════════════════════════╝",
                   g_KeyMarked ? TimeToString(g_KeyTime, TIME_MINUTES) : "──:──",
                   g_KeyHigh, g_KeyLow,
                   g_TradesToday, MaxTradesPerDay, spread,
                   SL_ticks, TP_ticks, rr,
                   g_Filling, GMT_Offset
                );

   string nm = "CTR_DB";
   if(ObjectFind(0, nm) < 0)
     {
      ObjectCreate(0, nm, OBJ_LABEL, 0, 0, 0);
      ObjectSetInteger(0, nm, OBJPROP_CORNER,    CORNER_LEFT_UPPER);
      ObjectSetInteger(0, nm, OBJPROP_XDISTANCE, 10);
      ObjectSetInteger(0, nm, OBJPROP_YDISTANCE, 20);
      ObjectSetInteger(0, nm, OBJPROP_FONTSIZE,  8);
      ObjectSetString (0, nm, OBJPROP_FONT,      "Courier New");
      ObjectSetInteger(0, nm, OBJPROP_BACK,      false);
     }
   ObjectSetString (0, nm, OBJPROP_TEXT,  txt);
   ObjectSetInteger(0, nm, OBJPROP_COLOR,
                    g_KeyMarked ? clrLimeGreen : clrGray);
  }

//+------------------------------------------------------------------+
//| Inicializar archivo CSV                                          |
//+------------------------------------------------------------------+
void InitCSV()
  {
   string dateStr = TimeToString(TimeCurrent(), TIME_DATE);
   StringReplace(dateStr, ".", "");
   string fname = "CTR_GBPUSD_v23_" + dateStr + ".csv";

   g_CSV = FileOpen(fname, FILE_WRITE | FILE_CSV | FILE_ANSI, ',');
   if(g_CSV == INVALID_HANDLE)
     {
      PrintFormat("[CTR] ERROR: No se pudo crear CSV '%s'", fname);
      return;
     }

   // Cabecera
   FileWrite(g_CSV,
             "Timestamp",
             "Dirección",
             "KeyCandleTime",
             "KeyHigh",
             "KeyLow",
             "KeyRangePips",
             "SweepBarTime",
             "SweepOpen",
             "SweepHigh",
             "SweepLow",
             "SweepClose",
             "EntryPrice",
             "SL",
             "TP",
             "SL_Real_pips",
             "TP_Real_pips",
             "RR",
             "Lotes",
             "BarrasDesdeKey",
             "SL_ticks_param",
             "TP_ticks_param",
             "Spread_pts",
             "GMT_Offset");
   PrintFormat("[CTR] CSV listo: %s", fname);
  }

//+------------------------------------------------------------------+
//| Escribir fila al CSV                                             |
//+------------------------------------------------------------------+
void WriteToCSV(ENUM_ORDER_TYPE ot, double lots, double entry,
                double sl, double tp, int barsAfterKey,
                double swHigh, double swLow, double swClose, double swOpen,
                double slDistActual)
  {
   if(g_CSV == INVALID_HANDLE) return;

   double pt      = m_symbol.Point();
   double spread  = (m_symbol.Ask() - m_symbol.Bid()) / pt;
   double slPips  = slDistActual / (pt * 10.0);
   double tpPips  = TP_ticks / 10.0;
   double rr      = (slPips > 0) ? tpPips / slPips : 0.0;
   double keyRange = (g_KeyHigh - g_KeyLow) / (pt * 10.0);

   FileWrite(g_CSV,
             TimeToString(TimeCurrent(), TIME_DATE | TIME_MINUTES),
             ot == ORDER_TYPE_BUY ? "BUY" : "SELL",
             TimeToString(g_KeyTime, TIME_DATE | TIME_MINUTES),
             DoubleToString(g_KeyHigh, _Digits),
             DoubleToString(g_KeyLow,  _Digits),
             DoubleToString(keyRange,  1),
             TimeToString(iTime(_Symbol, PERIOD_M5, 1), TIME_DATE | TIME_MINUTES),
             DoubleToString(swOpen,  _Digits),
             DoubleToString(swHigh,  _Digits),
             DoubleToString(swLow,   _Digits),
             DoubleToString(swClose, _Digits),
             DoubleToString(entry, _Digits),
             DoubleToString(sl,    _Digits),
             DoubleToString(tp,    _Digits),
             DoubleToString(slPips,  1),
             DoubleToString(tpPips,  1),
             DoubleToString(rr,      2),
             DoubleToString(lots,    2),
             IntegerToString(barsAfterKey),
             IntegerToString(SL_ticks),
             IntegerToString(TP_ticks),
             DoubleToString(spread,  1),
             IntegerToString(GMT_Offset));
  }

//+------------------------------------------------------------------+
//| OnTradeTransaction — log de fills en debug                       |
//+------------------------------------------------------------------+
void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest     &request,
                        const MqlTradeResult      &result)
  {
   if(!DebugMode) return;
   if(trans.type == TRADE_TRANSACTION_DEAL_ADD &&
      (trans.deal_type == DEAL_TYPE_BUY || trans.deal_type == DEAL_TYPE_SELL))
     {
      PrintFormat("[CTR] Deal ejecutado: ticket=%llu price=%.5f vol=%.2f",
                  trans.deal, trans.price, trans.volume);
     }
  }
