//|  ─ Retry sin SL/TP + modify, retry con lotMin por margen         |
//|  ─ Dashboard, CSV export, DrawLevels                             |
//|  ─ Fórmula timezone: Server = NY_EDT + 4 + GMT_Offset            |
//+------------------------------------------------------------------+
#property copyright "CTR Reclaim EA v2.4"
#property version   "2.40"
#property strict

#include <Trade\Trade.mqh>
#include <Trade\SymbolInfo.mqh>

//--- Enum dirección
enum ENUM_CTR_DIRECTION
  {
   DIR_BOTH = 0, // Both (Buy & Sell)
   DIR_BUY  = 1, // Buy Only
   DIR_SELL = 2  // Sell Only  ← default v2.4
  };

//=== INPUTS ============================================================

input group "══ IDENTIDAD ══"
input ulong  MagicNumber   = 1010; // Magic number
input bool   FilterByMagic = true; // Filtrar por magic

input group "══ RIESGO ══"
input double RiskPercent      = 1.0;   // Riesgo % por trade (sobre balance)
input double FixedLots        = 0.0;   // Lotes fijos (0 = auto)
input bool   UseEquityForRisk = false; // Usar equity en lugar de balance

input group "══ ESTRATEGIA ══"
input int                SL_ticks  = 110;      // Stop Loss en ticks (110 = 11 pips)
input int                TP_ticks  = 290;      // Take Profit en ticks (290 = 29 pips)
input ENUM_CTR_DIRECTION TradeDir  = DIR_SELL; // ★ SELL ONLY por defecto (v2.4)
input int                WindowBars = 12;      // Barras M5 post-key candle para buscar sweep

input group "══ FILTRO RANGO KEY CANDLE ══"
input bool   FilterKeyRange  = true;  // ★ Activar filtro de rango (v2.4)
input double KeyRangeMin_pip = 3.0;   // Rango mínimo key candle en pips (evita mercado muerto)
input double KeyRangeMax_pip = 25.0;  // Rango máximo key candle en pips (evita spike noticias)

input group "══ KEY CANDLE (HORA NY) ══"
input int NY_Hour           = 8;  // Hora en NY EDT (8 = 8 AM)
input int NY_Minute         = 45; // Minuto en NY
input int GMT_Offset        = 3;  // Offset servidor (3=FundingPips verano, 2=invierno)
input int ToleranceMinutes  = 1;  // Tolerancia ±min en búsqueda de key candle

input group "══ CIRCUIT BREAKER — DD DIARIO ══"
input bool   EnableDailyDD    = true;  // ★ Activar circuit breaker diario (v2.4)
input double MaxDailyDD_Pct   = 3.5;  // DD diario máximo % (FundingPips límite = 4%)
input bool   CloseOnDailyDD   = true;  // Cerrar posición abierta al activarse
input bool   AlertOnDailyDD   = true;  // Enviar alerta MT5 al activarse

input group "══ CIRCUIT BREAKER — DD SEMANAL ══"
input bool   EnableWeeklyDD   = true;  // ★ Activar circuit breaker semanal (v2.4)
input double MaxWeeklyDD_Pct  = 5.0;  // DD semanal máximo % (límite total FundingPips)

input group "══ SAFE MODE (TESTER) ══"
input bool   AutoSafeMode    = true;  // Padding dinámico de stops en tester
input int    SafePadPoints   = 6;     // Puntos extra al SL en safe mode
input bool   CheckH1Range    = true;  // Validar SL >= % del rango H1
input double H1RangeFactor   = 0.15; // SL mínimo = H1_range × factor

input group "══ DÍAS DE TRADING ══"
input bool TradeSunday    = false; // Domingo
input bool TradeMonday    = false; // Lunes
input bool TradeTuesday   = false; // Martes
input bool TradeWednesday = true;  // ★ Miércoles — 5/6 años rentables (SELL)
input bool TradeThursday  = false; // Jueves
input bool TradeFriday    = false; // Viernes

input group "══ FILTROS ══"
input int MaxTradesPerDay = 1;  // Máximo trades por día
input int MaxSpreadPoints = 30; // Spread máximo en puntos
input int SlippagePoints  = 10; // Slippage máximo

input group "══ BREAKEVEN / PARCIALES ══"
input bool   EnableBreakeven = false; // Activar breakeven
input double BreakevenPips   = 15.0;  // Pips de ganancia para mover BE
input bool   EnablePartials  = false; // Activar cierre parcial
input double PartialPips     = 14.0;  // Pips para parcial
input double PartialPercent  = 50.0;  // % volumen a cerrar

input group "══ DISPLAY & DIAGNÓSTICO ══"
input bool ShowDashboard = true;  // Panel en gráfico
input bool DrawLevels    = true;  // Líneas H/L key candle
input bool DebugMode     = false; // Logging detallado
input bool ExportCSV     = true;  // Exportar señales a CSV

//=== GLOBALES ==========================================================

CTrade      m_trade;
CSymbolInfo m_symbol;

//--- Key candle del día
double   g_KeyHigh   = 0.0;
double   g_KeyLow    = 0.0;
datetime g_KeyTime   = 0;
bool     g_KeyMarked = false;

//--- Estado diario
int      g_TradesToday   = 0;
datetime g_LastDate      = 0;
bool     g_PartialDone   = false;
double   g_DayOpenBalance = 0.0;   // Balance al inicio del día
bool     g_DailyDDHit    = false;  // Circuit breaker diario activado
string   g_DailyDDReason = "";     // Razón de activación para dashboard

//--- Estado semanal
datetime g_WeekStart       = 0;
double   g_WeekOpenBalance = 0.0;  // Balance al inicio de la semana
bool     g_WeeklyDDHit     = false;

//--- Key candle hora en servidor
int    g_SrvHour = 0;
int    g_SrvMin  = 0;

//--- Fill mode
string g_Filling = "RETURN";

//--- CSV
int    g_CSV = INVALID_HANDLE;

//--- Nueva barra detector
datetime g_LastBarTime = 0;

//+------------------------------------------------------------------+
//| OnInit                                                           |
//+------------------------------------------------------------------+
int OnInit()
  {
   if(!m_symbol.Name(_Symbol))
     {
      Print("[CTR] ERROR: símbolo no disponible — ", _Symbol);
      return INIT_FAILED;
     }
   m_symbol.Refresh();

   //--- Hora servidor para la key candle
   // Server = NY_EDT + 4 (UTC offset EDT) + GMT_Offset (broker)
   // FundingPips GMT+3 verano: 8 + 4 + 3 = 15:45 ✓
   g_SrvHour = (NY_Hour + 4 + GMT_Offset) % 24;
   g_SrvMin  = (NY_Minute / 5) * 5; // snap al grid M5

   //--- Validaciones de parámetros
   if(SL_ticks <= 0 || TP_ticks <= 0)
     {
      Print("[CTR] ERROR: SL/TP deben ser > 0");
      return INIT_PARAMETERS_INCORRECT;
     }
   if(MaxDailyDD_Pct <= 0 || MaxDailyDD_Pct > 20)
     {
      Print("[CTR] ERROR: MaxDailyDD_Pct fuera de rango");
      return INIT_PARAMETERS_INCORRECT;
     }
   if(KeyRangeMin_pip >= KeyRangeMax_pip && FilterKeyRange)
     {
      Print("[CTR] ERROR: KeyRangeMin >= KeyRangeMax");
      return INIT_PARAMETERS_INCORRECT;
     }

   DetectFillMode();

   m_trade.SetExpertMagicNumber(MagicNumber);
   m_trade.SetDeviationInPoints(SlippagePoints);
   m_trade.SetTypeFilling(GetFillingEnum());

   if(ExportCSV) InitCSV();

   //--- Inicializar balance semanal
   g_WeekOpenBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   g_WeekStart       = GetWeekStartTime(TimeCurrent());

   PrintFormat("[CTR v2.4] Init | %s M5 | KeyCandle: %02d:%02d srv | Fill: %s",
               _Symbol, g_SrvHour, g_SrvMin, g_Filling);
   PrintFormat("[CTR v2.4] Dir: %s | SL=%d tk | TP=%d tk | RR 1:%.2f | BE WR: %.1f%%",
               TradeDir==DIR_SELL ? "SELL ONLY" : TradeDir==DIR_BUY ? "BUY ONLY" : "BOTH",
               SL_ticks, TP_ticks,
               (double)TP_ticks/SL_ticks,
               100.0/(1.0 + (double)TP_ticks/SL_ticks));
   PrintFormat("[CTR v2.4] Días: %s%s%s%s%s | CB Diario: %.1f%% | CB Semanal: %.1f%%",
               TradeMonday    ? "Lun " : "",
               TradeTuesday   ? "Mar " : "",
               TradeWednesday ? "Mié " : "",
               TradeThursday  ? "Jue " : "",
               TradeFriday    ? "Vie"  : "",
               MaxDailyDD_Pct, MaxWeeklyDD_Pct);
   if(FilterKeyRange)
      PrintFormat("[CTR v2.4] Filtro rango key candle: %.1f – %.1f pips",
                  KeyRangeMin_pip, KeyRangeMax_pip);

   return INIT_SUCCEEDED;
  }

//+------------------------------------------------------------------+
//| OnDeinit                                                         |
//+------------------------------------------------------------------+
void OnDeinit(int reason)
  {
   if(g_CSV != INVALID_HANDLE) { FileClose(g_CSV); g_CSV = INVALID_HANDLE; }
   ObjectsDeleteAll(0, "CTR_");
  }

//+------------------------------------------------------------------+
//| OnTick — flujo principal                                         |
//+------------------------------------------------------------------+
void OnTick()
  {
   if(!m_symbol.RefreshRates()) return;

   datetime now = TimeCurrent();
   MqlDateTime dt;
   TimeToStruct(now, dt);

   //--- 1. Reset estado diario / semanal
   ResetDailyIfNeeded(dt);
   CheckWeeklyReset(now);

   //--- 2. Filtro de día de la semana
   if(!IsTradingDay(dt.day_of_week)) return;

   //--- 3. Circuit breakers — evaluar antes de cualquier otra cosa
   if(EnableWeeklyDD && g_WeeklyDDHit) return;
   CheckDailyDDCircuitBreaker();
   if(g_DailyDDHit) return;

   //--- 4. Marcar key candle
   if(!g_KeyMarked) TryScanKeyCandle(dt);
   if(!g_KeyMarked) return;

   //--- 5. Límite de trades del día
   if(g_TradesToday >= MaxTradesPerDay) return;

   //--- 6. Spread
   double spread = (m_symbol.Ask() - m_symbol.Bid()) / m_symbol.Point();
   if(spread > MaxSpreadPoints)
     {
      if(DebugMode) PrintFormat("[CTR] Spread alto: %.0f > %d — skip", spread, MaxSpreadPoints);
      return;
     }

   //--- 7. Señal en nueva barra
   datetime curBar = iTime(_Symbol, PERIOD_M5, 0);
   if(curBar != g_LastBarTime)
     {
      g_LastBarTime = curBar;
      CheckSweepSignal();
     }

   //--- 8. Gestión de posiciones abiertas
   if(EnableBreakeven || EnablePartials) ManageOpenPositions();

   //--- 9. Dashboard
   if(ShowDashboard) DrawDashboard(spread);
  }

//+------------------------------------------------------------------+
//| ① CIRCUIT BREAKER — DD DIARIO                                    |
//| Evalúa en cada tick si la equity cayó más de MaxDailyDD_Pct%    |
//| respecto al balance de apertura del día.                         |
//+------------------------------------------------------------------+
void CheckDailyDDCircuitBreaker()
  {
   if(!EnableDailyDD || g_DailyDDHit) return;
   if(g_DayOpenBalance <= 0) return;

   double equity  = AccountInfoDouble(ACCOUNT_EQUITY);
   double ddPct   = (g_DayOpenBalance - equity) / g_DayOpenBalance * 100.0;

   if(ddPct >= MaxDailyDD_Pct)
     {
      g_DailyDDHit    = true;
      g_DailyDDReason = StringFormat("DD %.2f%% >= límite %.1f%%", ddPct, MaxDailyDD_Pct);

      PrintFormat("[CTR] ⚠️ CIRCUIT BREAKER DIARIO activado: %s | Equity=%.2f | Balance=%.2f",
                  g_DailyDDReason,
                  equity, g_DayOpenBalance);

      if(AlertOnDailyDD)
         Alert(StringFormat("[CTR v2.4] Circuit Breaker Diario activado en %s: %s",
                             _Symbol, g_DailyDDReason));

      if(CloseOnDailyDD) CloseAllPositionsByMagic("CB_DailyDD");

      // Actualizar también el circuit breaker semanal
      if(EnableWeeklyDD) CheckWeeklyDDCircuitBreaker();
     }
  }

//+------------------------------------------------------------------+
//| ① CIRCUIT BREAKER — DD SEMANAL                                   |
//+------------------------------------------------------------------+
void CheckWeeklyDDCircuitBreaker()
  {
   if(!EnableWeeklyDD || g_WeeklyDDHit) return;
   if(g_WeekOpenBalance <= 0) return;

   double equity = AccountInfoDouble(ACCOUNT_EQUITY);
   double ddPct  = (g_WeekOpenBalance - equity) / g_WeekOpenBalance * 100.0;

   if(ddPct >= MaxWeeklyDD_Pct)
     {
      g_WeeklyDDHit = true;
      PrintFormat("[CTR] ⛔ CIRCUIT BREAKER SEMANAL activado: DD semanal %.2f%% >= %.1f%%",
                  ddPct, MaxWeeklyDD_Pct);
      if(AlertOnDailyDD)
         Alert(StringFormat("[CTR v2.4] Circuit Breaker SEMANAL activado en %s: %.2f%%",
                             _Symbol, ddPct));
     }
  }

//+------------------------------------------------------------------+
//| Cerrar todas las posiciones del EA                               |
//+------------------------------------------------------------------+
void CloseAllPositionsByMagic(const string reason)
  {
   for(int i = PositionsTotal()-1; i >= 0; i--)
     {
      ulong ticket = PositionGetTicket(i);
      if(!PositionSelectByTicket(ticket)) continue;
      if(FilterByMagic && PositionGetInteger(POSITION_MAGIC) != (long)MagicNumber) continue;
      if(PositionGetString(POSITION_SYMBOL) != _Symbol) continue;

      m_trade.PositionClose(ticket);
      if(DebugMode)
         PrintFormat("[CTR] Posición %llu cerrada por %s", ticket, reason);
     }
  }

//+------------------------------------------------------------------+
//| Reset estado diario                                              |
//+------------------------------------------------------------------+
void ResetDailyIfNeeded(const MqlDateTime &dt)
  {
   datetime today = StringToTime(StringFormat("%04d.%02d.%02d 00:00",
                                              dt.year, dt.mon, dt.day));
   if(today == g_LastDate) return;

   g_LastDate        = today;
   g_TradesToday     = 0;
   g_KeyMarked       = false;
   g_KeyHigh         = 0.0;
   g_KeyLow          = 0.0;
   g_KeyTime         = 0;
   g_PartialDone     = false;
   g_DailyDDHit      = false;
   g_DailyDDReason   = "";

   // Capturar balance de apertura del día
   g_DayOpenBalance  = AccountInfoDouble(ACCOUNT_BALANCE);

   ObjectDelete(0, "CTR_KH");
   ObjectDelete(0, "CTR_KL");
   ObjectDelete(0, "CTR_CB");  // Label de circuit breaker

   if(DebugMode)
      PrintFormat("[CTR] Nuevo día %s | Balance apertura: %.2f",
                  TimeToString(today, TIME_DATE), g_DayOpenBalance);
  }

//+------------------------------------------------------------------+
//| Reset semanal (lunes o primer día de la semana)                  |
//+------------------------------------------------------------------+
void CheckWeeklyReset(datetime now)
  {
   datetime ws = GetWeekStartTime(now);
   if(ws == g_WeekStart) return;

   g_WeekStart       = ws;
   g_WeekOpenBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   g_WeeklyDDHit     = false;

   if(DebugMode)
      PrintFormat("[CTR] Nueva semana | Balance apertura: %.2f", g_WeekOpenBalance);
  }

//+------------------------------------------------------------------+
//| Obtener inicio de semana (lunes 00:00)                           |
//+------------------------------------------------------------------+
datetime GetWeekStartTime(datetime t)
  {
   MqlDateTime md;
   TimeToStruct(t, md);
   // Retroceder al lunes
   int dow = md.day_of_week; // 0=Dom, 1=Lun...
   int daysBack = (dow == 0) ? 6 : dow - 1;
   datetime monDay = t - (datetime)(daysBack * 86400);
   MqlDateTime md2;
   TimeToStruct(monDay, md2);
   return StringToTime(StringFormat("%04d.%02d.%02d 00:00", md2.year, md2.mon, md2.day));
  }

//+------------------------------------------------------------------+
//| ¿Es día de trading?                                              |
//+------------------------------------------------------------------+
bool IsTradingDay(int dow)
  {
   switch(dow)
     {
      case 0: return TradeSunday;
      case 1: return TradeMonday;
      case 2: return TradeTuesday;
      case 3: return TradeWednesday;
      case 4: return TradeThursday;
      case 5: return TradeFriday;
      default: return false;
     }
  }

//+------------------------------------------------------------------+
//| Escanear key candle del día                                      |
//+------------------------------------------------------------------+
void TryScanKeyCandle(const MqlDateTime &dt)
  {
   int maxLook = MathMin(iBars(_Symbol, PERIOD_M5) - 1, 288);

   for(int i = 1; i < maxLook; i++)
     {
      datetime t = iTime(_Symbol, PERIOD_M5, i);
      MqlDateTime b;
      TimeToStruct(t, b);

      if(b.year != dt.year || b.mon != dt.mon || b.day != dt.day) break;

      bool hourMatch = (b.hour == g_SrvHour);
      int  minDiff   = MathAbs(b.min - g_SrvMin);
      if(minDiff > 30) minDiff = 60 - minDiff;
      bool minMatch  = (minDiff <= ToleranceMinutes);

      if(!hourMatch || !minMatch) continue;

      double hi = iHigh(_Symbol, PERIOD_M5, i);
      double lo = iLow (_Symbol, PERIOD_M5, i);

      //--- ② FILTRO DE RANGO KEY CANDLE
      if(FilterKeyRange)
        {
         double rangePips = (hi - lo) / (m_symbol.Point() * 10.0);
         if(rangePips < KeyRangeMin_pip)
           {
            if(DebugMode)
               PrintFormat("[CTR] Key candle descartada: rango %.1f pip < mínimo %.1f pip",
                           rangePips, KeyRangeMin_pip);
            return; // No marcar — mercado muerto esta sesión
           }
         if(rangePips > KeyRangeMax_pip)
           {
            if(DebugMode)
               PrintFormat("[CTR] Key candle descartada: rango %.1f pip > máximo %.1f pip (spike)",
                           rangePips, KeyRangeMax_pip);
            return; // No marcar — evento / spike de noticias
           }
        }

      g_KeyHigh   = hi;
      g_KeyLow    = lo;
      g_KeyTime   = t;
      g_KeyMarked = true;

      if(DebugMode)
         PrintFormat("[CTR] Key candle @ %s | H=%.5f L=%.5f | Rango=%.1f pips",
                     TimeToString(t, TIME_DATE|TIME_MINUTES),
                     g_KeyHigh, g_KeyLow,
                     (g_KeyHigh - g_KeyLow) / (m_symbol.Point() * 10.0));

      if(DrawLevels)
        {
         MakeHLine("CTR_KH", g_KeyHigh, clrDodgerBlue);
         MakeHLine("CTR_KL", g_KeyLow,  clrOrangeRed);
        }
      return;
     }
  }

//+------------------------------------------------------------------+
//| Detectar sweep y abrir trade                                     |
//+------------------------------------------------------------------+
void CheckSweepSignal()
  {
   if(!g_KeyMarked || g_TradesToday >= MaxTradesPerDay) return;

   datetime t1 = iTime(_Symbol, PERIOD_M5, 1);
   if(t1 <= g_KeyTime) return;

   long barsSinceKey = (long)((t1 - g_KeyTime) / PeriodSeconds(PERIOD_M5));
   if(barsSinceKey < 1 || barsSinceKey > (long)WindowBars) return;

   double hi = iHigh (_Symbol, PERIOD_M5, 1);
   double lo = iLow  (_Symbol, PERIOD_M5, 1);
   double cl = iClose(_Symbol, PERIOD_M5, 1);
   double op = iOpen (_Symbol, PERIOD_M5, 1);

   //--- Señales de sweep/reclaim
   bool sweepBuy  = (lo  < g_KeyLow)  && (cl > g_KeyLow);  // Low roto → cierra arriba
   bool sweepSell = (hi  > g_KeyHigh) && (cl < g_KeyHigh); // High roto → cierra abajo

   if(sweepBuy && sweepSell) return; // Doble sweep = señal ambigua
   if(!sweepBuy && !sweepSell) return;

   //--- Filtro de dirección
   ENUM_ORDER_TYPE orderType;
   if(sweepBuy  && TradeDir != DIR_SELL) orderType = ORDER_TYPE_BUY;
   else if(sweepSell && TradeDir != DIR_BUY) orderType = ORDER_TYPE_SELL;
   else return; // Dirección no permitida

   double pt  = m_symbol.Point();
   double ask = m_symbol.Ask();
   double bid = m_symbol.Bid();

   //--- Safe mode: padding + validación H1
   bool   inTester = (bool)MQLInfoInteger(MQL_TESTER) || (bool)MQLInfoInteger(MQL_OPTIMIZATION);
   int    safePad  = (AutoSafeMode && inTester) ? SafePadPoints : 0;
   double slDist   = SL_ticks * pt + safePad * pt;

   if(CheckH1Range && AutoSafeMode)
     {
      double h1R  = iHigh(_Symbol, PERIOD_H1, 1) - iLow(_Symbol, PERIOD_H1, 1);
      double slMin = h1R * H1RangeFactor;
      if(slDist < slMin)
        {
         if(DebugMode)
            PrintFormat("[CTR] SafeMode H1: SL ajustado %.5f→%.5f", slDist, slMin);
         slDist = slMin;
        }
     }

   double tpDist = TP_ticks * pt;
   double entry, sl, tp;

   if(orderType == ORDER_TYPE_BUY)
     {
      entry = ask;
      sl    = NormalizeDouble(entry - slDist, _Digits);
      tp    = NormalizeDouble(entry + tpDist, _Digits);
     }
   else
     {
      entry = bid;
      sl    = NormalizeDouble(entry + slDist, _Digits);
      tp    = NormalizeDouble(entry - tpDist, _Digits);
     }

   double lots = CalculateLots(slDist);
   if(lots <= 0.0) return;

   if(SendTrade(orderType, lots, entry, sl, tp))
     {
      g_TradesToday++;
      if(DebugMode)
         PrintFormat("[CTR] %s | lots=%.2f | entry=%.5f sl=%.5f tp=%.5f | bar %d post-key",
                     orderType==ORDER_TYPE_BUY ? "BUY" : "SELL",
                     lots, entry, sl, tp, (int)barsSinceKey);
      if(ExportCSV)
         WriteToCSV(orderType, lots, entry, sl, tp, (int)barsSinceKey,
                    hi, lo, cl, op, slDist);
     }
  }

//+------------------------------------------------------------------+
//| Calcular lotes con validación de margen                          |
//+------------------------------------------------------------------+
double CalculateLots(double slDistance)
  {
   if(FixedLots > 0.0) return FixedLots;

   double capital  = UseEquityForRisk
                     ? AccountInfoDouble(ACCOUNT_EQUITY)
                     : AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmt  = capital * RiskPercent / 100.0;
   double tickVal  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickSize <= 0.0 || tickVal <= 0.0) return 0.0;

   double slTicks = slDistance / tickSize;
   double rawLots = riskAmt / (slTicks * tickVal);

   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   double lots = MathMax(MathFloor(rawLots / lotStep) * lotStep, minLot);
   lots = MathMin(lots, maxLot);

   double margin = 0.0;
   if(OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, m_symbol.Ask(), margin))
     {
      if(margin > AccountInfoDouble(ACCOUNT_MARGIN_FREE) * 0.90)
        {
         if(DebugMode) Print("[CTR] Margen insuficiente → usando lote mínimo");
         lots = minLot;
        }
     }
   return lots;
  }

//+------------------------------------------------------------------+
//| Enviar orden con retries                                         |
//+------------------------------------------------------------------+
bool SendTrade(ENUM_ORDER_TYPE ot, double lots, double entry,
               double sl, double tp)
  {
   m_trade.SetTypeFilling(GetFillingEnum());

   bool ok = (ot == ORDER_TYPE_BUY)
             ? m_trade.Buy (lots, _Symbol, entry, sl, tp, "CTR v2.4 BUY")
             : m_trade.Sell(lots, _Symbol, entry, sl, tp, "CTR v2.4 SELL");

   if(!ok)
     {
      uint rc = m_trade.ResultRetcode();
      if(DebugMode)
         PrintFormat("[CTR] Rechazado rc=%u: %s", rc, m_trade.ResultComment());

      // Retry 1: stops inválidos → abrir sin SL/TP luego modify
      if(rc == 10016)
        {
         ok = (ot == ORDER_TYPE_BUY)
              ? m_trade.Buy (lots, _Symbol, entry, 0, 0, "CTR v2.4 BUY (noSL)")
              : m_trade.Sell(lots, _Symbol, entry, 0, 0, "CTR v2.4 SELL (noSL)");
         if(ok) { Sleep(400); FixStopsOnLastPosition(sl, tp); }
        }
      // Retry 2: sin margen → lote mínimo
      if(!ok && rc == 10019)
        {
         double ml = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
         ok = (ot == ORDER_TYPE_BUY)
              ? m_trade.Buy (ml, _Symbol, entry, sl, tp, "CTR v2.4 BUY (min)")
              : m_trade.Sell(ml, _Symbol, entry, sl, tp, "CTR v2.4 SELL (min)");
        }
     }
   return ok;
  }

//+------------------------------------------------------------------+
//| Modificar stops post-apertura (retry sin SL/TP)                  |
//+------------------------------------------------------------------+
void FixStopsOnLastPosition(double sl, double tp)
  {
   for(int i = PositionsTotal()-1; i >= 0; i--)
     {
      ulong ticket = PositionGetTicket(i);
      if(!PositionSelectByTicket(ticket)) continue;
      if(FilterByMagic && PositionGetInteger(POSITION_MAGIC) != (long)MagicNumber) continue;
      if(PositionGetString(POSITION_SYMBOL) != _Symbol) continue;
      m_trade.PositionModify(ticket, sl, tp);
      return;
     }
  }

//+------------------------------------------------------------------+
//| Gestión de posiciones: BE + Parciales                            |
//+------------------------------------------------------------------+
void ManageOpenPositions()
  {
   double pt = m_symbol.Point();

   for(int i = PositionsTotal()-1; i >= 0; i--)
     {
      ulong ticket = PositionGetTicket(i);
      if(!PositionSelectByTicket(ticket)) continue;
      if(FilterByMagic && PositionGetInteger(POSITION_MAGIC) != (long)MagicNumber) continue;
      if(PositionGetString(POSITION_SYMBOL) != _Symbol) continue;

      long   posType   = PositionGetInteger(POSITION_TYPE);
      double openPrice = PositionGetDouble(POSITION_PRICE_OPEN);
      double curSL     = PositionGetDouble(POSITION_SL);
      double curTP     = PositionGetDouble(POSITION_TP);
      double curPrice  = (posType == POSITION_TYPE_BUY) ? m_symbol.Bid() : m_symbol.Ask();
      double pnl       = (posType == POSITION_TYPE_BUY)
                         ? (curPrice - openPrice)
                         : (openPrice - curPrice);
      double profitPips = pnl / (pt * 10.0);

      //--- Parcial
      if(EnablePartials && !g_PartialDone && profitPips >= PartialPips)
        {
         double vol    = PositionGetDouble(POSITION_VOLUME);
         double step   = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
         double minL   = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
         double closeV = MathMax(MathFloor(vol * PartialPercent / 100.0 / step) * step, minL);
         if(closeV < vol)
           {
            m_trade.PositionClosePartial(ticket, closeV);
            g_PartialDone = true;
           }
        }

      //--- Breakeven
      if(EnableBreakeven && profitPips >= BreakevenPips)
        {
         double newSL;
         bool   needsUpdate;
         if(posType == POSITION_TYPE_BUY)
           {
            newSL       = NormalizeDouble(openPrice + pt, _Digits);
            needsUpdate = (curSL < newSL);
           }
         else
           {
            newSL       = NormalizeDouble(openPrice - pt, _Digits);
            needsUpdate = (curSL > newSL || curSL == 0.0);
           }
         if(needsUpdate) m_trade.PositionModify(ticket, newSL, curTP);
        }
     }
  }

//+------------------------------------------------------------------+
//| Detectar fill mode del broker                                    |
//+------------------------------------------------------------------+
void DetectFillMode()
  {
   uint fm = (uint)SymbolInfoInteger(_Symbol, SYMBOL_FILLING_MODE);
   if((fm & SYMBOL_FILLING_FOK) == SYMBOL_FILLING_FOK) g_Filling = "FOK";
   else if((fm & SYMBOL_FILLING_IOC) == SYMBOL_FILLING_IOC) g_Filling = "IOC";
   else g_Filling = "RETURN";
  }

ENUM_ORDER_TYPE_FILLING GetFillingEnum()
  {
   if(g_Filling == "FOK") return ORDER_FILLING_FOK;
   if(g_Filling == "IOC") return ORDER_FILLING_IOC;
   return ORDER_FILLING_RETURN;
  }

//+------------------------------------------------------------------+
//| Dibujar línea horizontal                                         |
//+------------------------------------------------------------------+
void MakeHLine(const string name, double price, color clr)
  {
   if(ObjectFind(0, name) >= 0) ObjectDelete(0, name);
   ObjectCreate(0, name, OBJ_HLINE, 0, 0, price);
   ObjectSetInteger(0, name, OBJPROP_COLOR, clr);
   ObjectSetInteger(0, name, OBJPROP_STYLE, STYLE_DASH);
   ObjectSetInteger(0, name, OBJPROP_WIDTH, 1);
   ObjectSetString (0, name, OBJPROP_TOOLTIP, name + "=" + DoubleToString(price, _Digits));
  }

//+------------------------------------------------------------------+
//| Dashboard on-chart — v2.4 incluye estado de circuit breakers    |
//+------------------------------------------------------------------+
void DrawDashboard(double spread)
  {
   double rr    = (SL_ticks > 0) ? (double)TP_ticks / SL_ticks : 0;
   double beWR  = 100.0 / (1.0 + rr);

   // DD diario actual
   double ddPct = 0.0;
   if(g_DayOpenBalance > 0)
      ddPct = (g_DayOpenBalance - AccountInfoDouble(ACCOUNT_EQUITY)) / g_DayOpenBalance * 100.0;

   // DD semanal actual
   double ddWeekPct = 0.0;
   if(g_WeekOpenBalance > 0)
      ddWeekPct = (g_WeekOpenBalance - AccountInfoDouble(ACCOUNT_EQUITY)) / g_WeekOpenBalance * 100.0;

   string cbDayStatus  = g_DailyDDHit  ? "🔴 BLOQUEADO"
                         : StringFormat("%.2f%% / %.1f%%", ddPct, MaxDailyDD_Pct);
   string cbWeekStatus = g_WeeklyDDHit ? "🔴 BLOQUEADO"
                         : StringFormat("%.2f%% / %.1f%%", ddWeekPct, MaxWeeklyDD_Pct);
   string dirStr       = TradeDir==DIR_SELL ? "SELL" : TradeDir==DIR_BUY ? "BUY" : "BOTH";

   string txt = StringFormat(
                   "╔══ CTR Reclaim v2.4 — GBPUSD M5 ══╗\n"
                   " Key:  %-5s  H: %.5f\n"
                   "                L: %.5f\n"
                   " Dir: %-4s  Trades: %d/%d  Sprd: %.0f\n"
                   " SL: %dtk  TP: %dtk  RR 1:%.2f  BE:%.1f%%\n"
                   " DD Día:  %s\n"
                   " DD Sem:  %s\n"
                   " Fill: %-6s  GMT+%d\n"
                   "╚════════════════════════════════════╝",
                   g_KeyMarked ? TimeToString(g_KeyTime, TIME_MINUTES) : "--:--",
                   g_KeyHigh, g_KeyLow,
                   dirStr, g_TradesToday, MaxTradesPerDay, spread,
                   SL_ticks, TP_ticks, rr, beWR,
                   cbDayStatus,
                   cbWeekStatus,
                   g_Filling, GMT_Offset
                );

   color txtColor = g_DailyDDHit  ? clrOrangeRed
                    : g_WeeklyDDHit ? clrOrange
                    : g_KeyMarked   ? clrLimeGreen
                    : clrGray;

   string nm = "CTR_DB";
   if(ObjectFind(0, nm) < 0)
     {
      ObjectCreate(0, nm, OBJ_LABEL, 0, 0, 0);
      ObjectSetInteger(0, nm, OBJPROP_CORNER,    CORNER_LEFT_UPPER);
      ObjectSetInteger(0, nm, OBJPROP_XDISTANCE, 10);
      ObjectSetInteger(0, nm, OBJPROP_YDISTANCE, 20);
      ObjectSetInteger(0, nm, OBJPROP_FONTSIZE,  8);
      ObjectSetString (0, nm, OBJPROP_FONT,      "Courier New");
     }
   ObjectSetString (0, nm, OBJPROP_TEXT,  txt);
   ObjectSetInteger(0, nm, OBJPROP_COLOR, txtColor);
  }

//+------------------------------------------------------------------+
//| CSV — init                                                       |
//+------------------------------------------------------------------+
void InitCSV()
  {
   string d = TimeToString(TimeCurrent(), TIME_DATE);
   StringReplace(d, ".", "");
   string fname = "CTR_GBPUSD_v24_" + d + ".csv";
   g_CSV = FileOpen(fname, FILE_WRITE | FILE_CSV | FILE_ANSI, ',');
   if(g_CSV == INVALID_HANDLE) { PrintFormat("[CTR] ERROR CSV: %s", fname); return; }
   FileWrite(g_CSV,
             "Timestamp","Dirección","KeyCandleTime","KeyHigh","KeyLow","KeyRangePips",
             "SweepBarTime","SwOpen","SwHigh","SwLow","SwClose",
             "Entry","SL","TP","SL_pips","TP_pips","RR","Lots","BarsPostKey",
             "SL_ticks","TP_ticks","Spread","GMT_Offset",
             "DayBalance","DailyDD_pct","WeekBalance","WeeklyDD_pct");
   PrintFormat("[CTR] CSV listo: %s", fname);
  }

//+------------------------------------------------------------------+
//| CSV — write row                                                  |
//+------------------------------------------------------------------+
void WriteToCSV(ENUM_ORDER_TYPE ot, double lots, double entry,
                double sl, double tp, int barsPostKey,
                double swHi, double swLo, double swCl, double swOp,
                double slDistActual)
  {
   if(g_CSV == INVALID_HANDLE) return;
   double pt      = m_symbol.Point();
   double spread  = (m_symbol.Ask() - m_symbol.Bid()) / pt;
   double slPips  = slDistActual / (pt * 10.0);
   double tpPips  = TP_ticks / 10.0;
   double rr      = (slPips > 0) ? tpPips / slPips : 0.0;
   double keyRng  = (g_KeyHigh - g_KeyLow) / (pt * 10.0);
   double ddDay   = (g_DayOpenBalance > 0)
                    ? (g_DayOpenBalance - AccountInfoDouble(ACCOUNT_EQUITY)) / g_DayOpenBalance * 100.0
                    : 0.0;
   double ddWeek  = (g_WeekOpenBalance > 0)
                    ? (g_WeekOpenBalance - AccountInfoDouble(ACCOUNT_EQUITY)) / g_WeekOpenBalance * 100.0
                    : 0.0;

   FileWrite(g_CSV,
             TimeToString(TimeCurrent(), TIME_DATE|TIME_MINUTES),
             ot == ORDER_TYPE_BUY ? "BUY" : "SELL",
             TimeToString(g_KeyTime, TIME_DATE|TIME_MINUTES),
             DoubleToString(g_KeyHigh, _Digits), DoubleToString(g_KeyLow, _Digits),
             DoubleToString(keyRng, 1),
             TimeToString(iTime(_Symbol, PERIOD_M5, 1), TIME_DATE|TIME_MINUTES),
             DoubleToString(swOp, _Digits), DoubleToString(swHi, _Digits),
             DoubleToString(swLo, _Digits), DoubleToString(swCl, _Digits),
             DoubleToString(entry, _Digits), DoubleToString(sl, _Digits), DoubleToString(tp, _Digits),
             DoubleToString(slPips, 1), DoubleToString(tpPips, 1), DoubleToString(rr, 2),
             DoubleToString(lots, 2), IntegerToString(barsPostKey),
             IntegerToString(SL_ticks), IntegerToString(TP_ticks),
             DoubleToString(spread, 1), IntegerToString(GMT_Offset),
             DoubleToString(g_DayOpenBalance, 2), DoubleToString(ddDay, 3),
             DoubleToString(g_WeekOpenBalance, 2), DoubleToString(ddWeek, 3));
  }

//+------------------------------------------------------------------+
//| OnTradeTransaction — log fills en debug                          |
//+------------------------------------------------------------------+
void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest     &req,
                        const MqlTradeResult      &res)
  {
   if(!DebugMode) return;
   if(trans.type == TRADE_TRANSACTION_DEAL_ADD &&
      (trans.deal_type == DEAL_TYPE_BUY || trans.deal_type == DEAL_TYPE_SELL))
      PrintFormat("[CTR] Deal: ticket=%llu price=%.5f vol=%.2f",
                  trans.deal, trans.price, trans.volume);
  }
