#property strict

#include <Trade\Trade.mqh>
#include <Trade\SymbolInfo.mqh>

enum ENUM_CTR_DIRECTION
  {
   DIR_BOTH = 0, // Both (Buy & Sell)
   DIR_BUY  = 1, // Buy Only
   DIR_SELL = 2  // Sell Only
  };

//=== INPUTS ============================================================

input group "══ IDENTIDAD ══"
input ulong  MagicNumber   = 1010;
input bool   FilterByMagic = true;

input group "══ RIESGO ══"
input double RiskPercent      = 1.0;
input double FixedLots        = 0.0;
input bool   UseEquityForRisk = false;

input group "══ ESTRATEGIA ══"
input int                SL_ticks   = 110;      // Stop Loss en ticks  [11 pips]
input int                TP_ticks   = 290;      // Take Profit en ticks [29 pips]
input ENUM_CTR_DIRECTION TradeDir   = DIR_SELL; // ★ SELL ONLY
input int                WindowBars = 12;

input group "══ FILTRO RANGO KEY CANDLE ══"
input bool   FilterKeyRange  = true;
input double KeyRangeMin_pip = 3.0;   // Mínimo pips — evita mercado muerto
input double KeyRangeMax_pip = 25.0;  // Máximo pips — evita spike noticias

input group "══ KEY CANDLE (HORA NY) ══"
input int NY_Hour          = 8;
input int NY_Minute        = 45;
input int GMT_Offset       = 3;  // FundingPips verano=3, invierno=2
